const express = require('express');
const crypto = require('crypto');

const app = express();
const PORT = 3000;

// Use express.raw middleware to capture the raw body for signature verification
app.post('/webhook', express.raw({ type: 'application/json' }), (req, res) => {
  // Get the signature from the header
  const signature = req.headers['x-prembly-signature'];

  // Check if signature header exists
  if (!signature) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Get the API key from environment variable
  const apiKey = process.env.PREMBLY_API_KEY;

  if (!apiKey) {
    console.error('PREMBLY_API_KEY environment variable is not set');
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Compute HMAC-SHA256 hash of the raw request body
  const hmac = crypto.createHmac('sha256', apiKey);
  hmac.update(req.body);
  const computedSignature = hmac.digest('base64');

  // Compare signatures securely
  if (computedSignature === signature) {
    // Signature is valid
    console.log('Webhook signature verified successfully');
    return res.status(200).json({ status: 'success' });
  } else {
    // Signature is invalid
    console.log('Invalid webhook signature');
    return res.status(401).json({ error: 'Invalid signature' });
  }
});

// Start the server
app.listen(PORT, () => {
  console.log(`Prembly webhook server is running on port ${PORT}`);
});

